import {
  circle, ellipse, rectangle, rounded_rectangle, polygon, triangle, segment, arc, ring,
  union, intersection, difference, dilate, erode, shell,
  render,
} from '../../src/index.js';

// ─── Palette ───────────────────────────────────────────────────────────────
const SKY_TOP    = [168, 195, 220];
const SKY_BOT    = [224, 215, 195];
const GROUND_C   = [148, 152, 120];
const STONE_C    = [210, 198, 172];
const STONE_D    = [188, 174, 148];   // darker stone, shadow sides
const WINDOW_C   = [140, 172, 210];   // stained-glass blue
const WINDOW_A   = [210, 140,  80];   // stained-glass amber
const ROSE_C     = [200, 120, 100];   // rose window centre
const OUTLINE    = [ 28,  22,  20];

// ─── Helpers ────────────────────────────────────────────────────────────────
// Pointed-arch ("lancet") window: rect body + triangular point
function lancet(cx, baseY, w, h, pointiness = 0.45) {
  const hw   = w / 2;
  const rectH = h * (1 - pointiness);
  const triH  = h * pointiness;
  return union(
    rectangle([w, rectH], [cx, baseY + rectH / 2]),
    polygon([
      [cx - hw, baseY + rectH],
      [cx + hw, baseY + rectH],
      [cx,      baseY + rectH + triH],
    ]),
  );
}

// Flying-buttress arm: a fat diagonal segment from (x0,y0) to (x1,y1)
function buttress(x0, y0, x1, y1, r = 0.022) {
  return segment([x0, y0], [x1, y1], r);
}

// ─── Ground ─────────────────────────────────────────────────────────────────
const ground = rectangle([2.6, 0.40], [0, -1.10]);

// ─── MAIN NAVE & TRANSEPT BODY ───────────────────────────────────────────────
// Central nave tower (tall, slightly narrower)
const naveTower = rectangle([0.38, 1.10], [0, -0.32]);

// Transept wings (lower horizontal cross-arm)
const transeptLeft  = rectangle([0.28, 0.60], [-0.33, -0.48]);
const transeptRight = rectangle([0.28, 0.60], [ 0.33, -0.48]);

// Choir (apse) — lower rectangular bulk at the base
const choir = rectangle([0.56, 0.32], [0, -0.90]);

// Combine stone body
const stone = union(naveTower, transeptLeft, transeptRight, choir, { k: 0.018 });

// ─── WEST FAÇADE (front face details) ───────────────────────────────────────
// Stringcourse bands
const stringcourse1 = intersection(stone, rectangle([2.5, 0.018], [0, -0.30]));
const stringcourse2 = intersection(stone, rectangle([2.5, 0.018], [0, -0.62]));

// ─── FLYING BUTTRESSES ──────────────────────────────────────────────────────
const butt1L = buttress(-0.19, -0.38, -0.44, -0.62, 0.018);
const butt2L = buttress(-0.19, -0.55, -0.44, -0.72, 0.018);
const butt1R = buttress( 0.19, -0.38,  0.44, -0.62, 0.018);
const butt2R = buttress( 0.19, -0.55,  0.44, -0.72, 0.018);
const buttresses = union(butt1L, butt2L, butt1R, butt2R);

// ─── TWIN BELL TOWERS (flanking the nave) ───────────────────────────────────
const towerL = rectangle([0.24, 1.52], [-0.50, 0.08]);
const towerR = rectangle([0.24, 1.52], [ 0.50, 0.08]);

// Tower pinnacles (pointed caps on the bell towers)
function spirePin(cx, baseY, w, h) {
  const hw = w / 2;
  return polygon([
    [cx - hw, baseY],
    [cx + hw, baseY],
    [cx,      baseY + h],
  ]);
}
const spireL = spirePin(-0.50, 0.84, 0.22, 0.32);
const spireR = spirePin( 0.50, 0.84, 0.22, 0.32);

// Central flèche (thin needle spire over crossing)
const fleche = polygon([
  [-0.045, 0.10],
  [ 0.045, 0.10],
  [ 0.018, 0.90],
  [-0.018, 0.90],
]);
const flecheSpire = polygon([
  [-0.018, 0.90],
  [ 0.018, 0.90],
  [     0, 1.14],
]);
const centralFlèche = union(fleche, flecheSpire);

// Small pinnacles on transept gables
const pinTransL = spirePin(-0.33, -0.18, 0.10, 0.18);
const pinTransR = spirePin( 0.33, -0.18, 0.10, 0.18);

// ─── ALL STONE (combined for outline base) ──────────────────────────────────
const allStone = union(
  stone, buttresses,
  towerL, towerR,
  spireL, spireR,
  centralFlèche,
  pinTransL, pinTransR,
);

// ─── PORTALS (ground-level lancet doors) ────────────────────────────────────
const portalC = lancet(    0, -1.00, 0.22, 0.50, 0.50); // centre portal, largest
const portalL = lancet(-0.38, -1.00, 0.15, 0.36, 0.50);
const portalR = lancet( 0.38, -1.00, 0.15, 0.36, 0.50);
const portals = union(portalC, portalL, portalR);

// ─── NAVE WINDOWS (tall lancets in nave) ────────────────────────────────────
const wNavL = lancet(-0.15, -0.72, 0.10, 0.34, 0.42);
const wNavR = lancet( 0.15, -0.72, 0.10, 0.34, 0.42);

// Transept aisle windows
const wTransLL = lancet(-0.38, -0.72, 0.10, 0.28, 0.42);
const wTransRR = lancet( 0.38, -0.72, 0.10, 0.28, 0.42);

// Clerestory windows (high up in the nave)
const wClerL = lancet(-0.12, -0.30, 0.08, 0.22, 0.42);
const wClerR = lancet( 0.12, -0.30, 0.08, 0.22, 0.42);

// Bell tower windows (paired, stacked)
function towerWindows(cx) {
  return union(
    lancet(cx, 0.14, 0.08, 0.18, 0.40),
    lancet(cx, 0.42, 0.08, 0.18, 0.40),
    lancet(cx, 0.64, 0.08, 0.14, 0.40),
  );
}
const twL = towerWindows(-0.50);
const twR = towerWindows( 0.50);

const allWindows = union(
  portals,
  wNavL, wNavR,
  wTransLL, wTransRR,
  wClerL, wClerR,
  twL, twR,
);

// ─── ROSE WINDOW ────────────────────────────────────────────────────────────
// Centre circle + 8 petal openings arranged circularly
const roseCentre = circle(0.044, [0, 0.04]);
const rosePetals = roseCentre.circular_array(8).scale(1).translate([0, 0]).union
  ? roseCentre  // fallback
  : roseCentre;

// Build the rose window as: outer ring difference of 8 small circles
function roseWindow(cx, cy, R) {
  const outer = ring(R, 0.016, [cx, cy]);
  const spoke1 = segment([cx, cy], [cx,       cy + R], 0.008);
  const spoke2 = segment([cx, cy], [cx,       cy - R], 0.008);
  const spoke3 = segment([cx, cy], [cx + R,   cy    ], 0.008);
  const spoke4 = segment([cx, cy], [cx - R,   cy    ], 0.008);
  const spoke5 = segment([cx, cy], [cx + R * 0.707, cy + R * 0.707], 0.008);
  const spoke6 = segment([cx, cy], [cx - R * 0.707, cy + R * 0.707], 0.008);
  const spoke7 = segment([cx, cy], [cx + R * 0.707, cy - R * 0.707], 0.008);
  const spoke8 = segment([cx, cy], [cx - R * 0.707, cy - R * 0.707], 0.008);
  const hub    = circle(R * 0.20, [cx, cy]);
  return union(outer, spoke1, spoke2, spoke3, spoke4,
               spoke5, spoke6, spoke7, spoke8, hub);
}

const rose        = roseWindow(0, 0.06, 0.118); // rose window graphic
const roseAperture = circle(0.118, [0, 0.06]);  // filled hole in stone

// ─── DARK-STONE SHADOW SIDES ─────────────────────────────────────────────────
// Shadow the right half of towers (simple vertical band intersection)
const shadowR = intersection(
  union(towerR, spireR),
  rectangle([0.12, 2.0], [0.50 + 0.06, 0.0]),
);
const shadowFlèche = intersection(
  centralFlèche,
  rectangle([0.04, 2.0], [0.01, 0.5]),
);

// ─── LAYERS ─────────────────────────────────────────────────────────────────
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');

render.silhouette(ctx, [
  // Ground
  { sdf: ground, color: GROUND_C },

  // Stone silhouette outline (dilate trick)
  { sdf: dilate(allStone, 0.028), color: OUTLINE },
  { sdf: allStone,                color: STONE_C  },

  // Darker stone shadow sides
  { sdf: shadowR,      color: STONE_D },
  { sdf: shadowFlèche, color: STONE_D },

  // Stringcourses (slightly darker band)
  { sdf: dilate(stringcourse1, 0.004), color: OUTLINE },
  { sdf: stringcourse1, color: STONE_D },
  { sdf: dilate(stringcourse2, 0.004), color: OUTLINE },
  { sdf: stringcourse2, color: STONE_D },

  // Stained-glass window fills (amber tint — warm light)
  { sdf: allWindows, color: WINDOW_A },

  // Window outlines (thin dark border)
  { sdf: dilate(allWindows, 0.010), color: OUTLINE },
  { sdf: allWindows,                color: WINDOW_A },

  // Clerestory & nave windows — cooler blue on top
  { sdf: union(wClerL, wClerR, wNavL, wNavR, twL, twR), color: WINDOW_C },

  // Rose window aperture fill
  { sdf: roseAperture, color: ROSE_C },
  // Rose window tracery (dark spokes over the fill)
  { sdf: rose, color: OUTLINE },

], {
  view: 1.25,
  background: { top: SKY_TOP, bottom: SKY_BOT },
});
```

